function App() {
  return (
    <BrowserRouter>
      <HeaderComponent />
      <main className="main-content">
        <div className="container">holaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa</div>
      </main>
      <FooterComponent />
    </BrowserRouter>
  );
}

export default App;
